        [Test]
        public void Constructor_DuplicateInChangeset_Throws()
        {
            // Arrange
            var user   = new NullUser();
            var crit   = new GameVersionCriteria(new GameVersion(1, 12, 5));
            var modGen = new RandomModuleGenerator(new Random());
            var mod    = modGen.GenerateRandomModule();
            var other  = modGen.GenerateRandomModule(identifier: mod.identifier);
            var inst   = new CkanModule[] { mod, other };
            using (var repo     = new TemporaryRepository(mod.ToJson(), other.ToJson()))
            using (var repoData = new TemporaryRepositoryData(user, repo.repo))
            {
                var registry = new CKAN.Registry(repoData.Manager, repo.repo);

                // Act / Assert
                var exc = Assert.Throws<ArgumentException>(() =>
                {
                    var sut = new RelationshipResolver(
                        inst, null,
                        RelationshipResolverOptions.DependsOnlyOpts(stabilityTolerance),
                        registry, game, crit);
                });
                Assert.AreEqual($"Already added {mod}, can't add {other} (Requested by user)",
                                exc?.Message);
            }
        }

        [Test]
        public void Constructor_WithRecommendationsThatConflictWithEachOther_ShowsAllInRecommendations()
        {
            // Arrange: Two mods (JNSQ and GPP) that conflict with each other,
            // both recommended by the same source mod
            var jnsq = generator!.GenerateRandomModule(identifier: "JNSQ");
            var gpp  = generator.GenerateRandomModule(identifier: "GPP");
            var opm  = generator.GenerateRandomModule(identifier: "OuterPlanetsMod");
            var kcal = generator.GenerateRandomModule(identifier: "KcalbelohSystem");
            var prom = generator.GenerateRandomModule(identifier: "PromisedWorldsCore");

            // JNSQ and GPP conflict with each other
            jnsq.conflicts = new List<RelationshipDescriptor>
            {
                new ModuleRelationshipDescriptor { name = gpp.identifier }
            };
            gpp.conflicts = new List<RelationshipDescriptor>
            {
                new ModuleRelationshipDescriptor { name = jnsq.identifier }
            };

            // A mod that recommends all of them
            var recommender = generator.GenerateRandomModule(identifier: "Recommender");
            recommender.recommends = new List<RelationshipDescriptor>
            {
                new ModuleRelationshipDescriptor { name = kcal.identifier },
                new ModuleRelationshipDescriptor { name = prom.identifier },
                new ModuleRelationshipDescriptor { name = jnsq.identifier },
                new ModuleRelationshipDescriptor { name = gpp.identifier  },
                new ModuleRelationshipDescriptor { name = opm.identifier  },
            };

            var user = new NullUser();
            using (var repo = new TemporaryRepository(
                jnsq.ToJson(), gpp.ToJson(), opm.ToJson(),
                kcal.ToJson(), prom.ToJson(), recommender.ToJson()))
            using (var repoData = new TemporaryRepositoryData(user, repo.repo))
            {
                var registry = new CKAN.Registry(repoData.Manager, repo.repo);
                var list = new List<CkanModule> { recommender };

                options!.with_recommends = true;
                options.proceed_with_inconsistencies = true;
                var relationship_resolver = new RelationshipResolver(list, null, options, registry, game, crit);

                // All recommended mods should be in the modlist, even if they conflict with each other
                CollectionAssert.Contains(relationship_resolver.ModList(), kcal);
                CollectionAssert.Contains(relationship_resolver.ModList(), prom);
                CollectionAssert.Contains(relationship_resolver.ModList(), jnsq);
                CollectionAssert.Contains(relationship_resolver.ModList(), gpp);
                CollectionAssert.Contains(relationship_resolver.ModList(), opm);

                // The two conflicting mods should be in the conflict list
                // (conflictList groups by UserReasonsFor, which may have 1 or more entries
                // depending on whether the conflicts are tracked through user_requested_mods)
                Assert.That(relationship_resolver.ConflictList.Keys,
                            Has.Some.EqualTo(recommender)
                               .Or.Some.EqualTo(jnsq)
                               .Or.Some.EqualTo(gpp));
                Assert.That(relationship_resolver.ConflictDescriptions.Any(
                    desc => desc.Contains(jnsq.identifier) && desc.Contains(gpp.identifier)),
                    "Conflict descriptions should mention both JNSQ and GPP");
            }
        }

        public static string MergeWithDefaults(string json)
        {
            var incoming = JObject.Parse(json);
            incoming.SafeMerge(moduleDefaults);
            return incoming.ToString();
        }

        public static IEnumerable<string> MergeWithDefaults(params string[] jsons)
            => jsons.Select(MergeWithDefaults);

        // Unimportant required fields that we don't want to duplicate
        private static readonly JObject moduleDefaults = JObject.Parse(
            @"{
                ""spec_version"": ""v1.34"",
                ""name"":         ""A mod or modpack"",
                ""author"":       ""An author"",
                ""version"":      ""1.0"",
                ""download"":     ""https://www.nonexistent.com/download""
            }");

    }
